INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TM000001', 'SITE000001', 'MAIL', 'ORDER_CONFIRM_MAIL', '주문 확인 메일', '[ShopJoy] 주문이 완료되었습니다', '<p>안녕하세요 {{username}}님,</p><p>주문번호 {{orderId}} 주문이 완료되었습니다.</p><p>감사합니다.</p>', '{"username":"홍길동","orderId":"ORD-20260410-001","prodNm":"블랙 데님 자켓","trackingNo":"1234567890","totalPrice":"89,000"}', 'Y', 'template.메일', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TM000002', 'SITE000001', 'MAIL', 'DELIVERY_START_MAIL', '배송 시작 알림 메일', '[ShopJoy] 상품이 출발했습니다', '<p>안녕하세요 {{username}}님,</p><p>주문하신 {{prodNm}} 상품이 배송 시작되었습니다.</p><p>운송장번호: {{trackingNo}}</p>', '{"username":"김민지","prodNm":"화이트 린넨 셔츠","trackingNo":"9876543210"}', 'Y', 'template.메일', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TM000003', 'SITE000001', 'MAIL', 'PW_RESET_MAIL', '비밀번호 재설정 메일', '[ShopJoy] 비밀번호 재설정 안내', '<p>안녕하세요,</p><p>비밀번호 재설정 링크: {{resetLink}}</p><p>링크는 24시간 후 만료됩니다.</p>', '{"resetLink":"https://shopjoy.example.com/reset?token=abc123xyz"}', 'Y', 'template.메일', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TM000004', 'SITE000001', 'MAIL', 'ORDER_COMPLETE_SMS', '주문완료 SMS', NULL, '[ShopJoy] {{username}}님 주문({{orderId}})이 완료되었습니다. 총 {{totalPrice}}원', '{"username":"이영희","orderId":"ORD-20260410-002","totalPrice":"45,000"}', 'Y', 'template.문자', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
