INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000001', 'SITE000001', '봄맞이 신상품 론칭 이벤트', 'PROMOTION', '봄맞이 신상품 론칭 이벤트', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#1a1a2e;">🌸 2026 봄 시즌 신상품 런칭</p><p>봄을 맞아 새로운 컬렉션을 소개합니다! 신선한 색감과 편안한 착용감이 특징인 봄 신상들이 도착했습니다.</p><ul style="margin:12px 0;padding-left:20px;"><li>최신 트렌드 반영 디자인</li><li>프리미엄 소재 사용</li><li>다양한 사이즈 준비</li></ul>', '2026-03-01', '2026-05-31', 'ACTIVE', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000002', 'SITE000001', 'VIP 회원 전용 특별 혜택', 'PROMOTION', 'VIP 회원 전용 특별 혜택', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#fbbf24;">👑 VIP 회원 전용 특가</p><p>VIP 고객님께 드리는 최고의 혜택! 일반 회원보다 더 저렴한 가격에 쇼핑하세요.</p>', '2026-04-01', '2026-04-30', 'ACTIVE', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000003', 'SITE000001', '설날 특별 기획전', 'PROMOTION', '설날 특별 기획전', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#c41e3a;">🧧 설날을 맞아 특별 기획전</p><p>명절의 따뜻함을 함께 나누는 ShopJoy의 설날 기획전에 초대합니다.</p>', '2026-01-15', '2026-02-10', 'END', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000004', 'SITE000001', '여름 시즌 프리뷰 이벤트', 'PROMOTION', '여름 시즌 프리뷰 이벤트', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#0891b2;">☀️ 2026 여름 시즌 프리뷰</p><p>여름 신상품을 미리 만나보는 특별한 기회!</p>', '2026-05-01', '2026-06-30', 'SCHEDULED', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000005', 'SITE000001', '신규 회원 가입 축하 이벤트', 'PROMOTION', '신규 회원 가입 축하 이벤트', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#7c3aed;">🎉 새로운 회원님을 환영합니다!</p><p>ShopJoy에 가입해주신 모든 회원님께 감사의 마음을 담은 선물을 준비했습니다.</p>', '2026-03-15', '2026-12-31', 'ACTIVE', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pm_event (event_id, site_id, event_nm, event_type_cd, event_title, event_content, start_date, end_date, event_status_cd, use_yn, reg_by, reg_date) VALUES ('EV000006', 'SITE000001', '브랜드 콜라보레이션 특가', 'PROMOTION', '브랜드 콜라보레이션 특가', '<p style="font-size:14px;font-weight:700;margin-bottom:12px;color:#ec4899;">💎 프리미엄 브랜드 콜라보</p><p>국내외 유명 브랜드와의 협력으로 특별한 제품들을 독점 출시합니다!</p>', '2026-04-10', '2026-05-31', 'ACTIVE', 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
